import React, { useState, useEffect, useCallback, useMemo } from 'react';
import axios from 'axios';
import io from 'socket.io-client';
import Navbar from "./components/Navbar";

// Conexión al servidor de expulsión (Super Usuario)
const socket = io('http://localhost:5000');

function App() {
  // --- SEGURIDAD Y SESIÓN ---
  const [token, setToken] = useState(localStorage.getItem('nitroToken') || '');
  const [isLoggedIn, setIsLoggedIn] = useState(!!localStorage.getItem('nitroToken'));
  const [userRole, setUserRole] = useState(localStorage.getItem('nitroRole') || 'vendedor');
  const [usuario, setUsuario] = useState(localStorage.getItem('nitroUser') || '');

  // --- LOGIN / REGISTRO ---
  const [authMode, setAuthMode] = useState('login'); 
  const [cred, setCred] = useState({ u: '', p: '', e: '', t: '', code: '' });
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  // --- INTERFAZ Y DATOS ---
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);
  const [filtroBajo, setFiltroBajo] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ n: '', s: '', p: '', f: null });

  // Configuración de API con Token JWT
  const api = axios.create({
    baseURL: 'http://localhost:5000/api',
    headers: { Authorization: `Bearer ${token}` }
  });

  const handleLogout = useCallback(() => {
    localStorage.clear();
    setToken('');
    setIsLoggedIn(false);
    setAuthMode('login');
  }, []);

  // ESCUCHAR SI EL SUPER USUARIO TE EXPULSA
  useEffect(() => {
    if (isLoggedIn && usuario) {
      socket.emit('register', usuario);
      socket.on('force_logout', () => {
        alert("🚨 HAS SIDO EXPULSADO POR EL SUPER ADMINISTRADOR");
        handleLogout();
      });
    }
    return () => socket.off('force_logout');
  }, [isLoggedIn, usuario, handleLogout]);

  const cargarDatos = useCallback(async () => {
    if (!isLoggedIn) return;
    setLoading(true);
    try {
      const [resS, resP] = await Promise.all([
        api.get('/stats'),
        api.get('/productos')
      ]);
      setStats(resS.data);
      setProductos(resP.data);
    } catch (e) {
      if (e.response?.status === 401) handleLogout();
    } finally {
      setLoading(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isLoggedIn, token, handleLogout]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  // --- BUSCADOR NITRO (LETRA POR LETRA) ---
  const buscarReal = useCallback(async (t) => {
    if (!t.trim()) { cargarDatos(); return; }
    try {
      const res = await api.get(`/productos/buscar?q=${t}`);
      setProductos(res.data);
    } catch (e) { console.error(e); }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token, cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    let timer;
    return (t) => {
      clearTimeout(timer);
      timer = setTimeout(() => buscarReal(t), 300);
    };
  }, [buscarReal]);

  // --- ACCIONES DE CUENTA ---
  const login = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario: cred.u, clave: cred.p });
      localStorage.setItem('nitroToken', res.data.token);
      localStorage.setItem('nitroRole', res.data.rol);
      localStorage.setItem('nitroUser', res.data.user);
      setToken(res.data.token);
      setUserRole(res.data.rol);
      setUsuario(res.data.user);
      setIsLoggedIn(true);
    } catch (e) { alert("Credenciales incorrectas"); }
  };

  const registrar = async () => {
    try {
      await axios.post('http://localhost:5000/api/register', { 
        usuario: cred.u, email: cred.e, telefono: cred.t, clave: cred.p, rol: nuevoRol, codigoAdmin: cred.code 
      });
      alert("¡Usuario registrado!");
      setAuthMode('login');
    } catch (e) { alert(e.response?.data?.error || "Error al registrar"); }
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4">
        <div className="bg-[#2d333b] p-8 rounded-[40px] shadow-2xl w-full max-w-sm text-white text-center">
          <h2 className="text-3xl font-black mb-6 uppercase tracking-tighter italic">Mi Tiendita Pro</h2>
          <div className="space-y-3 text-left">
            <input className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Usuario" onChange={e => setCred({...cred, u: e.target.value})} />
            {authMode === 'register' && (
              <>
                <input className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Email (Gmail)" onChange={e => setCred({...cred, e: e.target.value})} />
                <select className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" onChange={e => setNuevoRol(e.target.value)}>
                   <option value="vendedor">Vendedor</option>
                   <option value="admin">Administrador</option>
                </select>
                {nuevoRol === 'admin' && <input className="w-full bg-red-900/20 p-4 rounded-2xl border border-red-500 outline-none font-bold" placeholder="CÓDIGO ADMIN" onChange={e => setCred({...cred, code: e.target.value})} />}
              </>
            )}
            <input type="password" title="pass" className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Contraseña" onChange={e => setCred({...cred, p: e.target.value})} />
            <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-3xl text-lg uppercase transition active:scale-95 shadow-lg" onClick={authMode === 'login' ? login : registrar}>
              {authMode}
            </button>
            <p className="text-[10px] text-center text-gray-400 font-bold uppercase cursor-pointer" onClick={() => setAuthMode(authMode==='login'?'register':'login')}>
              {authMode==='login'?'¿Eres nuevo? Regístrate':'Volver al Login'}
            </p>
          </div>
        </div>
      </div>
    );
  }

  const filtrados = productos.filter(p => (filtroBajo ? p.stock < 10 : true));

  return (
    <div className="min-h-screen bg-gray-50 text-slate-800">
      <Navbar setView={setView} userRole={userRole} logout={handleLogout} busqueda={busqueda} handleBusquedaChange={e => {setBusqueda(e.target.value); optimizadaBusqueda(e.target.value)}} />

      {/* Barra de carga: QUITA EL WARNING DE "loading is not used" */}
      {loading && <div className="h-1.5 w-full bg-[#00c984] fixed top-[80px] z-50 animate-pulse"></div>}

      <main className="max-w-7xl mx-auto p-4 md:p-12">
        <h1 className="text-xl font-black mb-8 uppercase italic text-slate-400">Bienvenido: {usuario}</h1>

        {view === "dashboard" && busqueda === "" ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div onClick={() => {setView('inv'); setFiltroBajo(false)}} className="bg-white p-10 border rounded-[50px] shadow-xl text-center cursor-pointer hover:scale-105 transition">
              <p className="text-xs text-gray-400 font-black uppercase mb-2">Total</p>
              <p className="text-6xl font-black text-[#1e293b]">{stats.total_productos}</p>
            </div>
            <div onClick={() => {setView('inv'); setFiltroBajo(true)}} className="bg-white p-10 border rounded-[50px] shadow-xl text-center cursor-pointer hover:scale-105 transition">
              <p className="text-xs text-red-400 font-black uppercase mb-2 italic">Crítico</p>
              <p className="text-6xl font-black text-red-500">{stats.bajo_stock}</p>
            </div>
            <div className="bg-white p-10 border rounded-[50px] shadow-xl text-center">
              <p className="text-xs text-green-400 font-black uppercase mb-2">Capital</p>
              <p className="text-4xl md:text-5xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-black uppercase tracking-tighter italic">{busqueda ? `Resultados: ${busqueda}` : "Inventario"}</h2>
              {userRole === 'admin' && <button onClick={() => setShowForm(!showForm)} className="bg-[#1e293b] text-white px-8 py-3 rounded-2xl font-black text-xs uppercase shadow-lg italic"> {showForm ? 'Cerrar' : '+ Agregar'} </button>}
            </div>

            {showForm && (
              <div className="bg-white p-6 rounded-[40px] border-4 border-dashed grid grid-cols-1 md:grid-cols-5 gap-4">
                <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Nombre" onChange={e => setNuevoProd({...nuevoProd, n: e.target.value})} />
                <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Stock" type="number" onChange={e => setNuevoProd({...nuevoProd, s: e.target.value})} />
                <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Precio" type="number" onChange={e => setNuevoProd({...nuevoProd, p: e.target.value})} />
                <input type="file" className="text-xs mt-4" onChange={e => setNuevoProd({...nuevoProd, f: e.target.files[0]})} />
                <button className="bg-[#00c984] text-[#1e293b] font-black rounded-2xl py-4 uppercase shadow-lg" onClick={async () => {
                    const fd = new FormData(); fd.append('nombre', nuevoProd.n); fd.append('stock', nuevoProd.s); fd.append('precio_venta', nuevoProd.p); if (nuevoProd.f) fd.append('imagen', nuevoProd.f);
                    await api.post('/productos', fd); setShowForm(false); cargarDatos();
                }}>GUARDAR</button>
              </div>
            )}

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 md:gap-8">
              {filtrados.map(p => (
                <div key={p.id} className="bg-white p-4 md:p-6 rounded-[30px] md:rounded-[40px] shadow-xl border border-gray-100 text-center relative">
                  <img src={p.imagen ? `http://localhost:5000/uploads/${p.imagen}` : 'https://via.placeholder.com/150'} className="w-full h-32 md:h-40 object-cover rounded-3xl mb-4 shadow-sm" alt="p" />
                  <h3 className="font-black uppercase text-[10px] md:text-sm mb-1 line-clamp-1">{p.nombre}</h3>
                  <p className="text-green-600 font-black text-xl md:text-2xl">${p.precio_venta}</p>
                  {userRole === 'admin' && <button onClick={() => api.delete(`/productos/${p.id}`).then(()=>cargarDatos())} className="absolute top-2 right-2 text-red-300 hover:text-red-600 transition"><i className="fas fa-trash"></i></button>}
                </div>
              ))}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
